const normalize = (value) => String(value || "").trim().toLowerCase();

const findDestinationProfile = (destination) => {
  const normalized = normalize(destination);
  return destinationProfiles.find((profile) =>
    normalize(profile.destination) === normalized ||
    (profile.aliases || []).some((alias) => normalize(alias) === normalized)
  ) || null;
};

export const getDestinationImage = (destination) => {
  return findDestinationProfile(destination)?.heroImage?.url || null;
};

export const getDestinationProfile = (destination) => findDestinationProfile(destination);

export const getStaticMapImage = (coordinates) => {
  if (coordinates?.lat == null || coordinates?.lng == null) return null;
  return `https://staticmap.openstreetmap.de/staticmap.php?center=${coordinates.lat},${coordinates.lng}&zoom=14&size=800x600&markers=${coordinates.lat},${coordinates.lng},red-pushpin`;
};

export default {
  destinationProfiles,
  getDestinationImage,
  getDestinationProfile,
  getStaticMapImage
};
